					events: { beforeEventId: beforeEvent.id, afterEventId: afterEvent.id },
					callbackResult,
				},
				{ status: 409 },
			);
		}

		return Response.json({
			mode: "execute",
			prompt: promptSummary,
			startResult,
			codexResult: codexSummary,
			events: { beforeEventId: beforeEvent.id, afterEventId: afterEvent.id },
