  async writeFiles(params: {
    sandboxId: string;
    cwd: string;
    files: {
      path: string;
      content: string | Uint8Array;
      mode?: number;
    }[];
    extractDir: string;
    signal?: AbortSignal;
  }) {
    const { writer, response } = this.getFileWriter({
      sandboxId: params.sandboxId,
      extractDir: params.extractDir,
      signal: params.signal,
