    signal?: AbortSignal;
    blocking?: boolean;
  }): Promise<Parsed<z.infer<typeof SandboxResponse>>> {
    const url = `/v1/sandboxes/${params.sandboxId}/stop`;
    const response = await parseOrThrow(
      SandboxResponse,
      await this.request(url, { method: "POST", signal: params.signal }),
