   105	export function loadRhapsodySandboxEnv(env = process.env): RhapsodySandboxEnv | null {
   106		const values = {} as RhapsodySandboxEnv;
   107		const missing: string[] = [];
   108		const present: string[] = [];
   109	
   110		for (const key of SANDBOX_ENV_KEYS) {
   111			const value = env[key];
   112	
   113			if (!value?.trim()) {
   114				missing.push(key);
   115				continue;
   116			}
   117	
   118			present.push(key);
   119			values[key] = value;
   120		}
   121	
   122		if (present.length === 0) {
   123			return null;
   124		}
   125	
   126		if (missing.length > 0) {
   127			throw new RhapsodyConfigError([
   128				`Vercel Sandbox credentials must include all of ${SANDBOX_ENV_KEYS.join(", ")} when any are provided`,
   129				`Missing: ${missing.join(", ")}`,
   130			]);
   131		}
   132	
   133		return values;
   134	}
